marks = list(map(int, input().split()))
average = sum(marks) / 5
print(f"Average = {average:.2f}")

if average >= 90:
    print("Grade: A")
elif average >= 75:
    print("Grade: B")
elif average >= 60:
    print("Grade: C")
elif average >= 40:
    print("Grade: D")
else:
    print("Grade: F")
